parameters.query:
select * FROM mes.machine_data md
WHERE md.data ->>'bind_id'='{{ $json.battery_id }}' and md.data ->>'sn' = '{{ $json.sn }}'
and md.procedure_detail_id = {{ $json.procedureDetailId }}
and md.retroid_id = {{ $json.retroid_id }}
order by createtime DESC
limit 1

