const queryData = webhookData[0].json.body;
queryData.bind_id = $('将结果内空格、换行去除').all()[0].json.body.battery_id;

// 组织数据为一个对象
const result = {
  retroid_id: retroidId,
  procedure_detail_id: procedureDetailId,
  history_procedure_id: historyProcedureId,
