const sn = $('Webhook').first().json.body.sn;
const battery_id = $('Webhook').first().json.body.battery_id;
const procedure_name = 
$('Webhook').first().json.body.procedure_name
// 使用正则替换所有换行符（\n、\r）为空字符串
const cleanSn = sn.replace(/\s|\/n/g, '');
const cleanBid = battery_id.replace(/\s|\/n/g, '');
const cleanProcedure_name = procedure_name.replace(/\s|\/n/g, '');

// 返回清理后的数据
return {
  json: {
    body: {
            sn: cleanSn,
      battery_id: cleanBid,
      procedure_name: cleanProcedure_name
    }
  }
};

