// 从 Edit Fields 节点获取 retroid_id 数据
const editFieldsData = $("Edit Fields").all();
const retroidId = editFieldsData.length > 0 ? editFieldsData[0].json.retroid_id : null;

// 查找当前工序的数据
const currentProcedureIndex = inputData.findIndex(item => item.json.procedure_name === procedureNameFromWebhook);

// 确保找到了匹配的当前工序
if (currentProcedureIndex !== -1) {
  const currentProcedure = inputData[currentProcedureIndex].json;

  // 检查是否存在上一道工序
  const previousProcedure = currentProcedureIndex > 0 ? inputData[currentProcedureIndex - 1].json : null;

  // 返回结果
  return [
    {
      json: {
        currentProcedure: {
          procedure_name: currentProcedure.procedure_name,
          history_procedure_id: currentProcedure.history_procedure_id,
          procedure_detail_id: currentProcedure.procedure_detail_id,
        },
        previousProcedure: previousProcedure ? {
          procedure_name: previousProcedure.procedure_name,
          history_procedure_id: previousProcedure.history_procedure_id,
          procedure_detail_id: previousProcedure.procedure_detail_id,
        } : null,
        retroidId: retroidId
      }
    }
  ];
}

